const formResponse = $input.first().json.body.form_response;

const hidden = formResponse.hidden || {};
const customerEmail = hidden.email || '';
const firstName = hidden.first_name || '';
const lastName = hidden.last_name || '';
const userId = hidden.user_id || '';

const answerMap = {};
for (const answer of (formResponse.answers || [])) {
  const fieldId = answer.field.id;
  let value;
  switch (answer.type) {
    case 'text': value = answer.text || ''; break;
    case 'choice': value = answer.choice ? answer.choice.label : ''; break;
    case 'choices': value = answer.choices ? answer.choices.labels.join(', ') : ''; break;
    case 'number': value = answer.number || 0; break;
    default: value = answer[answer.type] || '';
  }
  answerMap[fieldId] = value;
}

const fieldIds = Object.keys(answerMap);
const process_name = answerMap[fieldIds[0]] || '';
const frustration_type = answerMap[fieldIds[1]] || '';
const monthly_volume_raw = String(answerMap[fieldIds[2]] || '0');
const time_per_instance_raw = answerMap[fieldIds[3]] || '';
const hourly_rate_raw = answerMap[fieldIds[4]] || '';
const error_rate_raw = answerMap[fieldIds[5]] || '';
const tools_involved = answerMap[fieldIds[6]] || '';
const decision_complexity_raw = answerMap[fieldIds[7]] || '';
const ideal_state = answerMap[fieldIds[8]] || '';
const freed_time_impact = answerMap[fieldIds[9]] || '';

const timeNorm = {
  '5-15 minutes': '5-15min', '15-30 minutes': '15-30min',
  '30-60 minutes': '30-60min', '1-2 hours': '1-2hrs',
  '2+ hours': '2+hrs', 'More than 2 hours': '2+hrs'
};
const time_per_instance = timeNorm[time_per_instance_raw] || time_per_instance_raw || '15-30min';

const rateNorm = {
  '$50-75/hr': '$50-75/hr', '$75-100/hr': '$75-100/hr',
  '$100-150/hr': '$100-150/hr', '$150+/hr': '$150+/hr',
  'Not sure': '$75-100/hr'
};
const hourly_rate = rateNorm[hourly_rate_raw] || hourly_rate_raw || '$75-100/hr';

const errorNorm = {
  'Rarely (under 2%)': 'Rarely (<2%)', 'Rarely (<2%)': 'Rarely (<2%)',
  'Occasionally (~5%)': 'Occasionally (~5%)',
  'Often (10%+)': 'Often (10%+)', 'Often (10% or more)': 'Often (10%+)'
};
const error_rate = errorNorm[error_rate_raw] || error_rate_raw || 'Occasionally (~5%)';

const compNorm = {
  'Simple rules, no judgment needed': 'Simple rules / no judgment',
  'Simple rules / no judgment': 'Simple rules / no judgment',
  'Mostly rules with occasional judgment': 'Simple rules with occasional judgment calls',
  'Simple rules with occasional judgment calls': 'Simple rules with occasional judgment calls',
  'Requires context or experience': 'Requires context or experience',
  'Highly subjective or relationship-dependent': 'Highly subjective / relationship-dependent'
};
const decision_complexity = compNorm[decision_complexity_raw] || decision_complexity_raw || 'Simple rules with occasional judgment calls';

const numbers = monthly_volume_raw.match(/\d+/g);
let monthly_volume = 0;
if (numbers && numbers.length >= 2) {
  monthly_volume = Math.round((parseInt(numbers[0]) + parseInt(numbers[1])) / 2);
} else if (numbers && numbers.length === 1) {
  monthly_volume = parseInt(numbers[0]);
}

const now = new Date();
const ms = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const report_date = `${ms[now.getMonth()]} ${now.getDate()}, ${now.getFullYear()}`;

return [{ json: {
  customer_email: customerEmail, first_name: firstName, last_name: lastName, user_id: userId,
  process_name, frustration_type, monthly_volume, monthly_volume_raw,
  time_per_instance, hourly_rate, error_rate, tools_involved,
  decision_complexity, ideal_state, freed_time_impact, report_date
}}];

const intake = $('Parse Typeform').first().json;
const engagement = $input.first().json;

let clientName = '';
const companyField = engagement.fields ? engagement.fields.Company : engagement.Company;
if (companyField) {
  if (Array.isArray(companyField)) {
    clientName = companyField[0] || '';
  } else if (typeof companyField === 'string') {
    clientName = companyField;
  }
}
if (!clientName) {
  clientName = [intake.first_name, intake.last_name].filter(Boolean).join(' ') || 'Client';
}

return [{ json: { ...intake, client_name: clientName } }];

// Reference intake data from Extract Company Name node (has all fields + client_name)
const intake = $('Extract Company Name').first().json;

const timeMidpoints = {
  '5-15min': 10, '15-30min': 22.5, '30-60min': 45, '1-2hrs': 90, '2+hrs': 150
};
const rateMidpoints = {
  '$50-75/hr': 62.50, '$75-100/hr': 87.50, '$100-150/hr': 125.00, '$150+/hr': 175.00
};
const errorDecimals = {
  'Rarely (<2%)': 0.02, 'Occasionally (~5%)': 0.05, 'Often (10%+)': 0.12
};

const timeMinutes = timeMidpoints[intake.time_per_instance] || 22.5;
const hourlyRate = rateMidpoints[intake.hourly_rate] || 87.50;
const errorDecimal = errorDecimals[intake.error_rate] || 0.05;
const volume = parseInt(intake.monthly_volume) || 0;

// Core calculations
const monthlyHoursRaw = (volume * timeMinutes) / 60;
// Realism cap: if raw hours > 100, cap at 80%
const monthlyHours = monthlyHoursRaw > 100
  ? Math.round(monthlyHoursRaw * 0.8)
  : Math.round(monthlyHoursRaw);

const monthlyCost = Math.round(monthlyHours * hourlyRate);
const annualCost = monthlyCost * 12;
const reworkCost = Math.round(monthlyCost * errorDecimal * 1.5);

// Format numbers with commas
const fmt = (n) => n.toLocaleString('en-US');

return [{
  json: {
    // Raw values for further calculation
    time_minutes_midpoint: timeMinutes,
    hourly_rate_midpoint: hourlyRate,
    error_rate_decimal: errorDecimal,
    monthly_hours: monthlyHours,
    monthly_cost: monthlyCost,
    annual_cost: annualCost,
    rework_cost: reworkCost,
    // Display formatted (with commas)
    monthly_hours_display: fmt(monthlyHours),
    monthly_cost_display: fmt(monthlyCost),
    annual_cost_display: fmt(annualCost),
    rework_cost_display: fmt(reworkCost)
  }
}];

// Reference intake data with client_name
const d = $('Extract Company Name').first().json;

const userMessage = `Here is the intake data for this AI Time Audit:

Business Name: ${d.client_name}
Process Being Audited: ${d.process_name}
Primary Frustration: ${d.frustration_type}
Monthly Volume: ${d.monthly_volume} times per month
Time Per Instance: ${d.time_per_instance}
Hourly Rate of Person Doing Work: ${d.hourly_rate}
Error/Rework Rate: ${d.error_rate}
Tools Currently Involved: ${d.tools_involved}
Decision Complexity: ${d.decision_complexity}
Ideal State (client's words): "${d.ideal_state}"
What Team Would Do With Freed Time: "${d.freed_time_impact}"`;

return [{
  json: {
    ai_user_message: userMessage
  }
}];

const p1 = $('P1 Automation Pct').first().json;
const metrics = $('Calculate Metrics').first().json;

// Parse automation percentage from Anthropic output
let rawText = (p1.text || p1.content || JSON.stringify(p1)).trim();
let pct = parseInt(rawText);

// Validate: must be 30-85, divisible by 5
if (isNaN(pct) || pct < 30 || pct > 85) {
  pct = 55; // Safe fallback (conservative middle)
}
if (pct % 5 !== 0) {
  pct = Math.round(pct / 5) * 5;
}

// Calculate savings using validated percentage
const timeSavingsMonthly = Math.round(metrics.monthly_hours * (pct / 100));
const costSavingsMonthly = Math.round(metrics.monthly_cost * (pct / 100));
const costSavingsAnnual = costSavingsMonthly * 12;

// Payback period: assume $5,000 implementation mid-range
const implCost = 5000;
const paybackMonths = costSavingsMonthly > 0
  ? Math.ceil(implCost / costSavingsMonthly)
  : 0;
const paybackDisplay = paybackMonths <= 1
  ? '1 month'
  : paybackMonths <= 2
    ? '1-2 months'
    : `${paybackMonths - 1}-${paybackMonths} months`;

return [{
  json: {
    automation_percentage: pct,
    time_savings_monthly: timeSavingsMonthly,
    cost_savings_monthly: costSavingsMonthly,
    cost_savings_annual: costSavingsAnnual,
    payback_period: paybackDisplay,
    time_savings_monthly_display: timeSavingsMonthly.toLocaleString(),
    cost_savings_monthly_display: costSavingsMonthly.toLocaleString(),
    cost_savings_annual_display: costSavingsAnnual.toLocaleString()
  }
}];

// Gather all data from upstream nodes
const intake = $('Extract Company Name').first().json;
const metrics = $('Calculate Metrics').first().json;
const savings = $('Validate Pct and Savings').first().json;

// AI outputs (simplified Anthropic returns {text: "..."})
const automatableSteps = $('P2 Automatable Steps').first().json.text || '';
const humanSteps = $('P3 Human Steps').first().json.text || '';
const solutionApproach = $('P4 Solution Approach').first().json.text || '';
const intTriggerRaw = $('P5 Integrations Trigger').first().json.text || '';
const exceptionHandling = $('P6 Exception Handling').first().json.text || '';

// Parse Prompt 5 two-line output
const lines = intTriggerRaw.split('\n');
let keyIntegrations = '';
let triggerEvent = '';
for (const line of lines) {
  if (line.startsWith('KEY_INTEGRATIONS:')) {
    keyIntegrations = line.replace('KEY_INTEGRATIONS:', '').trim();
  }
  if (line.startsWith('TRIGGER_EVENT:')) {
    triggerEvent = line.replace('TRIGGER_EVENT:', '').trim();
  }
}

// Derive remaining_human_work from first human step
const humanStepLines = humanSteps.split('\n').filter(l => l.trim().startsWith('-'));
const remainingHumanWork = humanStepLines.length > 0
  ? humanStepLines[0].replace('- ', '').toLowerCase().trim()
  : 'tasks requiring judgment';

// Validation
const validationIssues = [];
const autoStepCount = automatableSteps.split('\n').filter(l => l.trim().startsWith('-')).length;
if (autoStepCount < 3 || autoStepCount > 6) {
  validationIssues.push(`automatable_steps has ${autoStepCount} bullets (expected 3-6)`);
}
if (humanStepLines.length < 2 || humanStepLines.length > 4) {
  validationIssues.push(`human_required_steps has ${humanStepLines.length} bullets (expected 2-4)`);
}
if (!solutionApproach.trim().startsWith('The automation would')) {
  validationIssues.push('solution_approach does not start with "The automation would"');
}
if (!keyIntegrations) {
  validationIssues.push('key_integrations could not be parsed from Prompt 5');
}
if (!triggerEvent) {
  validationIssues.push('trigger_event could not be parsed from Prompt 5');
}
const exceptionWords = exceptionHandling.trim().split(/\s+/).length;
if (exceptionWords < 8 || exceptionWords > 20) {
  validationIssues.push(`exception_handling is ${exceptionWords} words (expected 8-20)`);
}

return [{
  json: {
    ...intake,
    ...metrics,
    ...savings,
    automatable_steps: automatableSteps,
    human_required_steps: humanSteps,
    solution_approach: solutionApproach,
    key_integrations: keyIntegrations,
    trigger_event: triggerEvent,
    exception_handling: exceptionHandling,
    remaining_human_work: remainingHumanWork,
    validation_issues: validationIssues,
    validation_passed: validationIssues.length === 0
  }
}];

const d = $('Parse All AI Outputs').first().json;
const documentId = $('Copy Template').first().json.id;

const r = (key, fallback = '') => {
  const val = d[key];
  return val !== undefined && val !== null ? String(val) : fallback;
};

// Build placeholder keys using charCode to avoid n8n expression parsing
const b = (name) => String.fromCharCode(123, 123) + name + String.fromCharCode(125, 125);

const fieldMap = {
  'client_name': 'client_name',
  'process_name': 'process_name',
  'report_date': 'report_date',
  'monthly_hours': 'monthly_hours_display',
  'monthly_cost': 'monthly_cost_display',
  'annual_cost': 'annual_cost_display',
  'error_rate': 'error_rate',
  'rework_cost': 'rework_cost_display',
  'frustration_type': 'frustration_type',
  'tools_involved': 'tools_involved',
  'decision_complexity': 'decision_complexity',
  'freed_time_impact': 'freed_time_impact',
  'automation_percentage': 'automation_percentage',
  'automatable_steps': 'automatable_steps',
  'human_required_steps': 'human_required_steps',
  'remaining_human_work': 'remaining_human_work',
  'solution_approach': 'solution_approach',
  'key_integrations': 'key_integrations',
  'trigger_event': 'trigger_event',
  'exception_handling': 'exception_handling',
  'time_savings_monthly': 'time_savings_monthly_display',
  'cost_savings_monthly': 'cost_savings_monthly_display',
  'cost_savings_annual': 'cost_savings_annual_display',
  'payback_period': 'payback_period'
};

const replacements = {};
for (const [placeholder, field] of Object.entries(fieldMap)) {
  replacements[b(placeholder)] = r(field);
}
replacements[b('booking_link_15min')] = 'https://calendly.com/atomi-agency/15min';
replacements[b('booking_link_strategy')] = 'https://calendly.com/atomi-agency/strategy';

const requests = Object.entries(replacements).map(([placeholder, value]) => ({
  replaceAllText: {
    containsText: {
      text: placeholder,
      matchCase: true
    },
    replaceText: value
  }
}));

return [{
  json: {
    documentId,
    requests,
    report_url: 'https://docs.google.com/document/d/' + documentId + '/edit'
  }
}];

const d = $('Parse All AI Outputs').first().json;
const reportUrl = $('Build Replacements').first().json.report_url;
const inputBinary = $input.first().binary || {};

const emailHtml = `<p>Hi ${d.client_name},</p><p>Your AI Time Audit is complete. Please find your report attached.</p><p>Here is a quick summary:</p><ul><li>Process audited: ${d.process_name}</li><li>Current monthly cost: $${d.monthly_cost_display}</li><li>Estimated automation potential: ${d.automation_percentage}%</li><li>Projected monthly savings: $${d.cost_savings_monthly_display}</li></ul><p>The report includes three options for what to do next. If you would like to discuss the findings, the quickest way is to book a free 15-minute call:</p><p><a href="https://calendly.com/atomi-agency/15min">Book a Call</a></p><p>Questions? Just reply to this email.</p><p>Jeremy<br>Atomi Agency</p>`;

const validStatus = d.validation_passed ? 'PASSED' : 'ISSUES: ' + (d.validation_issues || []).join(', ');
const teamsMsg = 'New AI Time Audit report ready for review.\n\nClient: ' + d.client_name + '\nProcess: ' + d.process_name + '\nAutomation: ' + d.automation_percentage + '%\nMonthly savings: $' + d.cost_savings_monthly_display + '\n\nGoogle Doc: ' + reportUrl + '\n\nValidation: ' + validStatus + '\n\nAction required: Review draft email in Outlook, then send.';

return [{
  json: {
    email_html: emailHtml,
    email_subject: 'Your AI Time Audit Report is Ready - ' + d.client_name,
    email_to: d.customer_email,
    teams_message: teamsMsg,
    intake_record_id: $('Create Intake Record').first().json.id,
    automation_percentage: d.automation_percentage,
    cost_savings_monthly: d.cost_savings_monthly,
    report_url: reportUrl,
    validation_issues: d.validation_issues || []
  },
  binary: inputBinary
}];
